import java.util.Scanner;
import java.util.Date;
import java.text.SimpleDateFormat;

/**
 * Task 1: Ticket Booking System
 * Description: Calculates train fare based on distance travelled.
 */
public class TrainBookingSystem {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        System.out.println("==========================================");
        System.out.println("          IRCTC TRAIN BOOKING             ");
        System.out.println("==========================================");

        System.out.print("Enter Source Station      : ");
        String source = sc.nextLine();
        System.out.print("Enter Destination Station : ");
        String dest = sc.nextLine();

        System.out.print("Enter Distance (in km)    : ");
        int distance = Integer.parseInt(sc.nextLine());

        double farePerKm = 0.0;

        System.out.println("\n--- Select Class ---");
        System.out.println("1. Sleeper Class (SL) - Rs. 1.50/km");
        System.out.println("2. AC 3 Tier (3A) - Rs. 3.00/km");
        System.out.println("3. AC 2 Tier (2A) - Rs. 4.50/km");
        System.out.print("Choice: ");
        int classChoice = Integer.parseInt(sc.nextLine());

        String className = "";
        switch(classChoice) {
            case 1: farePerKm = 1.50; className = "Sleeper Class"; break;
            case 2: farePerKm = 3.00; className = "AC 3 Tier"; break;
            case 3: farePerKm = 4.50; className = "AC 2 Tier"; break;
            default: farePerKm = 1.00; className = "General"; break;
        }

        double totalFare = distance * farePerKm;
        // Base charge
        totalFare += 50.0;

        System.out.println("\n==========================================");
        System.out.println("             E-TICKET DETAILS             ");
        System.out.println("==========================================");
        SimpleDateFormat formatter = new SimpleDateFormat("dd-MMM-yyyy HH:mm:ss");
        System.out.println("Transaction Date: " + formatter.format(new Date()));
        System.out.println("Passenger Name  : {studentName}");
        System.out.println("Passenger ID    : {rollNumber}");
        System.out.println("------------------------------------------");
        System.out.println("From            : " + source);
        System.out.println("To              : " + dest);
        System.out.println("Distance        : " + distance + " KM");
        System.out.println("Class           : " + className);
        System.out.println("------------------------------------------");
        System.out.printf("Total Fare      : Rs. %.2f\n", totalFare);
        System.out.println("==========================================");
        System.out.println("         WISH YOU A HAPPY JOURNEY!        ");
        sc.close();
    }
}

import java.util.Scanner;
import java.util.Date;
import java.text.SimpleDateFormat;

/**
 * Task 2: Text Encryption & Decryption
 * Description: Encrypts and decrypts text using a basic Caesar cipher shift.
 */
public class TextCrypto {

    public static String encrypt(String text, int shift) {
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < text.length(); i++) {
            char ch = text.charAt(i);
            // Encrypt uppercase
            if (Character.isUpperCase(ch)) {
                result.append((char) (((int) ch + shift - 65) % 26 + 65));
            }
            // Encrypt lowercase
            else if (Character.isLowerCase(ch)) {
                result.append((char) (((int) ch + shift - 97) % 26 + 97));
            }
            // Keep spaces/symbols intact
            else {
                result.append(ch);
            }
        }
        return result.toString();
    }

    public static String decrypt(String text, int shift) {
        return encrypt(text, 26 - (shift % 26));
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        System.out.println("=== SECURE TEXT CIPHER ENGINE ===");
        System.out.println("Operator: {studentName} ({rollNumber})");
        SimpleDateFormat formatter = new SimpleDateFormat("yyyy/MM/dd HH:mm:ss");
        System.out.println("Timestamp: " + formatter.format(new Date()));
        System.out.println("---------------------------------");

        System.out.print("Enter text to encrypt: ");
        String message = sc.nextLine();
        System.out.print("Enter numeric key (shift): ");
        int shift = Integer.parseInt(sc.nextLine());

        String encryptedMessage = encrypt(message, shift);
        String decryptedMessage = decrypt(encryptedMessage, shift);

        System.out.println("\n--- PROCESSING ---...");
        System.out.println("Original Message  : " + message);
        System.out.println("\n[ ENCRYPTED OUTPUT ] -> " + encryptedMessage);
        System.out.println("\n[ DECRYPTING... ]");
        System.out.println("Restored Message  : " + decryptedMessage);

        System.out.println("\n=== PROCESS COMPLETE ===");
        sc.close();
    }
}

import java.util.Random;
